import{_ as a,o,c as t,a3 as n}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"135. Public Holidays","description":"","frontmatter":{"title":"135. Public Holidays","eba":"Mental Health Services 2024-2028","topics":["leave","public-holidays","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/health-professionals/leave/135-public-holidays.md","filePath":"ebas/mental-health/health-professionals/leave/135-public-holidays.md"}'),r={name:"ebas/mental-health/health-professionals/leave/135-public-holidays.md"};function s(l,e,i,h,d,y){return o(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="_135-public-holidays" tabindex="-1">135. Public Holidays <a class="header-anchor" href="#_135-public-holidays" aria-label="Permalink to &quot;135. Public Holidays&quot;">​</a></h1><p>Note: For requirements for requests to work on a Public Holiday, see <a href="/eba/ebas/mental-health/health-professionals/hours-of-work/124-roster.html">clause 124</a> Rosters.</p><p><strong>135.1</strong> Entitlement An Employee shall be entitled to holidays on the following days:</p><p><strong>(a)</strong> New Year&#39;s Day, Good Friday, Easter Saturday, Easter Sunday, Easter Monday, Christmas Day and Boxing Day; and</p><p><strong>(b)</strong> the following days, as prescribed in the relevant States, Territories and localities: Australia Day, Anzac Day, King&#39;s Birthday, Eight Hour Day or Labour Day; the Friday before the AFL Grand Final; and</p><p><strong>(c)</strong> Melbourne Cup Day or in lieu of Melbourne Cup Day, some other day as determined in a particular locality.</p><p><strong>135.2</strong> Holidays in lieu</p><p><strong>(a)</strong> When Christmas Day is a Saturday or a Sunday, a holiday in lieu thereof shall be observed on 27 December.</p><p><strong>(b)</strong> When Boxing Day is a Saturday or a Sunday, a holiday in lieu thereof shall be observed on 28 December.</p><p><strong>(c)</strong> When New Year&#39;s Day or Australia Day is a Saturday or a Sunday, a holiday in lieu thereof shall be observed on the next Monday.</p><p><strong>135.3</strong> Additional days Where public holidays are declared or prescribed on days other than those set out in clause</p><p><strong>135.1</strong> and clause 135.2 above in Victoria or a locality thereof, those days shall, as applicable, constitute additional holidays for the purpose of this Part F.</p><p><strong>135.4</strong> Penalty Payments in respect of public holidays</p><p><strong>(a)</strong> An Employee, other than a casual, who performs work (including overtime work) on a public holiday (or where Christmas Day, Boxing Day, New Year&#39;s Day or Australia Day fall on a weekend, the day to which penalty rates apply) shall be entitled to be paid:</p><p><strong>(i)</strong> 200% (based on 1/38th of the weekly salary set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>) for the time worked on a public holiday Monday to Friday; or</p><p><strong>(ii)</strong> 250% (based on 1/38th of the weekly salary set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>) for the time worked on a public holiday on a Saturday or Sunday (which is inclusive of the rates in sub-<a href="/eba/ebas/mental-health/health-professionals/hours-of-work/130-saturday-and-sunday-work.html">clause 130</a>).</p><p><strong>(b)</strong> A casual Employee who performs work (including overtime work) on a public holiday (or where Christmas Day, Boxing Day, New Year&#39;s Day or Australia Day fall on a weekend, the day to which penalty rates apply pursuant to clause 135.2) shall be entitled to be paid inclusive of the casual loading;</p><p><strong>(i)</strong> 250% (based on 1/38th of the weekly salary set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>) for time worked on a public holiday Monday to Friday; or</p><p><strong>(ii)</strong> 312.5% (based on 1/38th of the weekly salary set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>) for time worked on a public holiday on a Saturday or Sunday (which is inclusive of the rates in sub-<a href="/eba/ebas/mental-health/health-professionals/hours-of-work/130-saturday-and-sunday-work.html">clause 130</a> above).</p><p><strong>135.5</strong> Public Holiday not required to work</p><p>Where a public holiday occurs on a day that a part-time or full-time Employee would normally work, but the Employee is not required by the Employer to work on that day, the Employee will be paid an amount equal to the Employee&#39;s ordinary rate of pay for the hours the Employee would normally have worked on that day.</p><p><strong>135.6</strong> Public Holidays occurring on rostered day off</p><p><strong>(a)</strong> If holidays occur on their rostered day off they shall be paid at the ordinary time rate of pay for the time so worked, in addition to which they shall be entitled to receive:</p><p><strong>(i)</strong> within four weeks following the date on which such holiday occurred <strong>(A)</strong> one and a half extra day&#39;s pay <strong>(B)</strong> one and a half days off in lieu thereof of which at least seven days&#39; notice shall be given <strong>(C)</strong> one and a half days shall be added to their annual leave</p><p><strong>(ii)</strong> in the case of an Employee not qualifying for annual leave and where neither of the provisions of sub-clause 135.6(a)(i) have been applied the one and a half days&#39; pay shall be added to the payment in lieu of annual leave; and</p><p><strong>(iii)</strong> one and a half times the ordinary time rate of pay for any work done in excess of eight hours.</p><p><strong>(b)</strong> Notwithstanding the earlier provisions of this clause a shiftworker (as defined in <a href="/eba/ebas/mental-health/rpn-pen-mho/preliminary/70-definitions-specific-to-section-2.html">clause 70.1</a>(b) who works on any of the holidays set out in clause 135.1, shall be entitled (in lieu of any entitlement under clause 135.2) to one and a half extra days&#39; pay on the first pay day following the end of the pay period during which the holiday falls.</p><p><strong>(c)</strong> If, at the end of the yearly period in respect of which their annual leave accrues such shiftworker does not become entitled to additional leave under clause they shall, at the option of the Employer, be entitled to one and a half extra days&#39; pay or one and a half extra days&#39; annual leave for each such holiday on which they were rostered off.</p><p><strong>(i)</strong> Notwithstanding the provisions of clause 135.2, an Employee who is ordinarily not required to work on a Sunday or Saturday shall not be entitled to any benefit for any public holidays which may fall on or are observed on a Saturday or a Sunday unless they are required to work on any such public holiday.</p><p><strong>135.7</strong> Accrued Days off on Public Holidays</p><p><strong>(a)</strong> Where an Employee&#39;s accrued day off falls on any such public holiday, a substitute day shall be determined by the Employer to be taken in lieu thereof, such day to be within the same four-week cycle where practical.</p><p><strong>135.8</strong> Substitution of public holidays by agreement</p><p><strong>(a)</strong> The Employer and the Employees may agree to substitute another day for any prescribed in this clause. For this purpose, the consent of the majority of affected Employees shall constitute agreement.</p><p><strong>(b)</strong> An agreement pursuant to clause 135.8(a) shall be recorded in writing and be available to every affected Employee.</p><p><strong>135.9</strong> Conversion of Public Holiday penalties to Leave</p><p><strong>(a)</strong> An Employee who works a public holiday and is entitled to public holiday penalties may elect to convert their penalties entitlement to the following:</p><p><strong>(i)</strong> be allowed another half day and receive an additional half day&#39;s ordinary pay; or</p><p><strong>(ii)</strong> receive an additional sum equal to a day&#39;s ordinary pay for that day.</p><p><strong>(b)</strong> An Employee who makes an election under this provision shall be entitled to convert the fifty per cent component of the public holiday penalty prescribed by this subclause to be taken up to a maximum of five days additional leave added to either their annual leave or long service leave and taken pursuant to the annual leave/long service leave provisions of this agreement, but shall not attract annual leave loading.</p><p><strong>(c)</strong> An Employee who wishes to convert these provisions must advise their Employer of their election to do so before the beginning of a calendar year. This election remains in force until the Employee discontinues this benefit in writing or ceases to work a roster that requires them to work on Public Holidays. An Employee may only discontinue their election before the commencement of another calendar year.</p><p><strong>(d)</strong> Employees who work Monday to Friday and who are not ordinarily required to work public holidays as they fall are eligible to accrue and take the additional leave in accordance with sub-clause 135.7 provided that:</p><p><strong>(i)</strong> the Employee advises their Employer at the beginning of each calendar year that they are available to work on a public holiday, and</p><p><strong>(ii)</strong> the Employer, at its discretion, requests the Employee to work the public holiday and the Employee agrees and works that public holiday.</p><p>Plain language terms: public holiday pay, holiday pay, PH pay, penalty rates holidays.</p>',44)])])}const c=a(r,[["render",s]]);export{u as __pageData,c as default};
